def dna_assemble(fragments):
    if not fragments:
        return ""
    seen = set()
    unique = []
    for f in fragments:
        if f not in seen:
            seen.add(f)
            unique.append(f)
    n = len(unique)
    is_sub = [False] * n
    for i in range(n):
        for j in range(n):
            if i != j and unique[i] in unique[j]:
                is_sub[i] = True
                break
    fragments = [unique[i] for i in range(n) if not is_sub[i]]
    n = len(fragments)
    if n == 0:
        return ""
    if n == 1:
        return fragments[0]
    def get_overlap(a, b):
        mx = min(len(a), len(b))
        for k in range(mx, 0, -1):
            if b.startswith(a[-k:]):
                return k
        return 0
    ov = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i != j:
                ov[i][j] = get_overlap(fragments[i], fragments[j])
    full = (1 << n) - 1
    INF = float('inf')
    dp = [[INF] * n for _ in range(1 << n)]
    for i in range(n):
        dp[1 << i][i] = len(fragments[i])
    for mask in range(1, 1 << n):
        for last in range(n):
            if not (mask & (1 << last)) or dp[mask][last] == INF:
                continue
            for nxt in range(n):
                if mask & (1 << nxt):
                    continue
                nm = mask | (1 << nxt)
                c = dp[mask][last] + len(fragments[nxt]) - ov[last][nxt]
                if c < dp[nm][nxt]:
                    dp[nm][nxt] = c
    min_len = min(dp[full])
    remain = [[INF] * n for _ in range(1 << n)]
    for i in range(n):
        remain[full][i] = 0
    for mask in range(full - 1, 0, -1):
        for i in range(n):
            if not (mask & (1 << i)):
                continue
            for j in range(n):
                if mask & (1 << j):
                    continue
                nm = mask | (1 << j)
                if remain[nm][j] == INF:
                    continue
                c = len(fragments[j]) - ov[i][j] + remain[nm][j]
                if c < remain[mask][i]:
                    remain[mask][i] = c
    best_tail = [[None] * n for _ in range(1 << n)]
    for i in range(n):
        best_tail[full][i] = ""
    for mask in range(full - 1, 0, -1):
        for i in range(n):
            if not (mask & (1 << i)) or remain[mask][i] == INF:
                continue
            for j in range(n):
                if mask & (1 << j):
                    continue
                nm = mask | (1 << j)
                if remain[nm][j] == INF or best_tail[nm][j] is None:
                    continue
                extra = len(fragments[j]) - ov[i][j]
                if extra + remain[nm][j] == remain[mask][i]:
                    cand = fragments[j][ov[i][j]:] + best_tail[nm][j]
                    if best_tail[mask][i] is None or cand < best_tail[mask][i]:
                        best_tail[mask][i] = cand
    best = None
    for i in range(n):
        mask = 1 << i
        if dp[mask][i] + remain[mask][i] == min_len and best_tail[mask][i] is not None:
            cand = fragments[i] + best_tail[mask][i]
            if best is None or cand < best:
                best = cand
    return best

