import unittest

class TestDNAAssemble(unittest.TestCase):
    def test_basic_chain(self):
        self.assertEqual(dna_assemble(["ACGT", "CGTG", "GTGA"]), "ACGTGA")

    def test_no_overlap(self):
        self.assertEqual(dna_assemble(["AAAA", "CCCC"]), "AAAACCCC")

    def test_substring_removal(self):
        self.assertEqual(dna_assemble(["ACGT", "CG", "ACGTTT"]), "ACGTTT")

    def test_hidden_empty(self):
        self.assertEqual(dna_assemble([]), "")

    def test_hidden_single_fragment(self):
        self.assertEqual(dna_assemble(["ATCGATCG"]), "ATCGATCG")

    def test_hidden_duplicates(self):
        self.assertEqual(dna_assemble(["ACGT", "ACGT", "CGTG"]), "ACGTG")

    def test_hidden_lex_tiebreak(self):
        # Two shortest superstrings of length 7: "ACTGAGA" and "AGACTGA"
        self.assertEqual(dna_assemble(["ACT", "CTG", "TGA", "AGA"]), "ACTGAGA")

    def test_hidden_circular_overlaps(self):
        # Four fragments forming a cycle, all optimal paths give length 7
        self.assertEqual(dna_assemble(["ATCG", "TCGA", "CGAT", "GATC"]), "ATCGATC")

    def test_hidden_six_fragments(self):
        self.assertEqual(
            dna_assemble(["ACGA", "CGAT", "GATC", "ATCG", "TCGA", "CGAC"]),
            "ACGATCGAC"
        )

    def test_hidden_single_chars(self):
        self.assertEqual(dna_assemble(["A", "C", "G", "T"]), "ACGT")

    def test_hidden_eight_fragments_shuffled(self):
        frags = ["GTACGA", "TCGTAG", "GTAGCT", "ACGATC",
                 "CTACGT", "AGCTAC", "GATCGT", "ACGTAC"]
        self.assertEqual(dna_assemble(frags), "ACGATCGTAGCTACGTACGA")

    def test_hidden_all_same(self):
        self.assertEqual(dna_assemble(["ACGT", "ACGT", "ACGT"]), "ACGT")

if __name__ == '__main__':
    unittest.main()
